INSERT IGNORE INTO `sys_movie` VALUES (1, '八角笼中', 120, '[\"/images/movie/2023/07/08/b62fd514a5b7408e9cd41b228b1195b9.jpg\"]', '中国大陆', '2023-07-08 12:25:20', 266.00, '年度最受期待现实佳作！根据真实事件改编，王宝强诚意打造普通人改写命运之路！', '[\"/images/movie/2023/07/08/d719ce09e35347999b243847f1eab610.jpg\", \"/images/movie/2023/07/08/e56b01ef8b2748a4812760ff94ccffcc.jpg\", \"/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg\", \"/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg\", \"/images/movie/2023/07/08/f5c6d4b533a6433faaa74f972cfe6bce.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (2, '消失的她', 120, '[\"/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg\"]', '中国大陆', '2023-07-08 12:25:27', 348.00, '金牌监制陈思诚继《误杀》系列后又一悬疑力作，朱一龙、倪妮、文咏珊、杜江俊男美女狂飙演技，剧情过山车反转停不下来！', '[\"/images/movie/2023/07/08/a546b6b4277844328dc1e4c52c9c6a69.jpg\", \"/images/movie/2023/07/08/b37d19c3ae304aefb6ef8bf99437e85d.jpg\", \"/images/movie/2023/07/08/a64c759d80e746b9a6c80b1181cd6ca0.jpg\", \"/images/movie/2023/07/08/c62af834ee5c49d29b9d7e17a0133d64.jpg\", \"/images/movie/2023/07/08/9c7b4cff4fa8438393df319c6d58a195.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (3, '长安三万里', 120, '[\"/images/movie/2023/07/08/a284e9179d954164b15448ef25277df3.jpg\"]', '中国大陆', '2023-07-07 12:25:31', 0.00, '安史之乱爆发后数年，吐蕃大军攻打西南。大唐节度使高适交战不利，长安岌岌可危。困守孤城的高适向监军太监回忆起自己与李白的一生往事。', '[\"/images/movie/2023/07/08/51bec9afe30045f78d456dd27f50f6db.jpg\", \"/images/movie/2023/07/08/f2d5f2baf63f4316b025a04d29cd2cbb.jpg\", \"/images/movie/2023/07/08/b93b27fa19214cc9b4a4c45876e1c866.jpg\", \"/images/movie/2023/07/08/559b24d427a2427885424af59dce96c9.jpg\", \"/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (4, '扫毒3：人在天涯', 120, '[\"/images/movie/2023/07/08/bbaadec5d93e4c9ca5f7b69592833c51.jpg\"]', '中国大陆', '2023-07-08 12:25:35', 0.00, '邱礼涛继《扫毒2》《拆弹专家2》后携《扫毒3：人在天涯》强势回归，古天乐郭富城刘青云三大影帝首次同台飙戏荡平金三角！', '[\"/images/movie/2023/07/08/5f4fe51072604f4f8462b4ec48099949.jpg\", \"/images/movie/2023/07/08/a1fd14630e0d448ba64fba9a9041fbba.jpg\", \"/images/movie/2023/07/08/6126fc55631047a3b07d27ad4e71372c.jpg\", \"/images/movie/2023/07/08/bbf4b074d6f649508d25f798bc2ff8bc.jpg\", \"/images/movie/2023/07/08/e79f8b5cc069451ca305ffc39597524c.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (5, '封神第一部', 120, '[\"/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg\"]', '中国大陆', '2023-07-07 12:25:41', 0.00, '中国国民神话史诗大片，震撼视效燃炸暑期！三千年想象成真，恢弘史诗再创新，见证中国神话崛起！', '[\"/images/movie/2023/07/08/57c6d183aa94440fb1ba794c6a38deae.jpg\", \"/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg\", \"/images/movie/2023/07/08/f1c5db2c9ed44e419736713ec46f741c.jpg\", \"/images/movie/2023/07/08/5c4f08c6670a4a0f95f34a8ba1b25c7c.jpg\", \"/images/movie/2023/07/08/7bffc009cb3c4ba2a93c37c7ad0de204.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (6, '我爱你！', 120, '[\"/images/movie/2023/07/08/fe5caaf26e54486089581917d79fcbaf.jpg\"]', '中国大陆', '2023-07-07 12:25:46', 0.00, '影帝影后绝赞演技，年度爱情片神作，带你领悟爱情真谛。四个花甲老人，两段迟暮之恋。', '[\"/images/movie/2023/07/08/5e54da8a222a43b7a8ea6b440a693a42.jpg\", \"/images/movie/2023/07/08/b3bc5af799354b18b77d0a402a0a0332.jpg\", \"/images/movie/2023/07/08/87ba4f68fae34520a2b664038564ba28.jpg\", \"/images/movie/2023/07/08/c111499f7068491bb3bbf99714ab1c61.jpg\", \"/images/movie/2023/07/08/d5116527077e4f30939eb58703a51460.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (7, '变形金刚：超能勇士崛起', 130, '[\"/images/movie/2023/07/08/e04f06dc02b84d38bc4d1ba2b39add0d.jpg\"]', '美国', '2023-07-07 12:25:49', 0.00, '2023年顶级大银幕视觉盛宴来袭！时隔5年，变形金刚震撼归来！', '[\"/images/movie/2023/07/08/abd8b63064cb41babbb8d9c1608daebb.jpg\", \"/images/movie/2023/07/08/67e51c6e84bd49efa0abbd6d7262a7cd.jpg\", \"/images/movie/2023/07/08/d6eb9956a31942bebac3ef8f3e65f1fe.jpg\", \"/images/movie/2023/07/08/f0ee1b5dc1a446cba6f90b577f3fa203.jpg\", \"/images/movie/2023/07/08/a9dc4522a74f4441b941b6c72442bcb5.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (8, '超级飞侠：乐迪加速', 140, '[\"/images/movie/2023/07/08/c940dfecf0fc4ced810c8107f0182f02.png\"]', '中国大陆', '2023-07-08 12:25:56', 0.00, '超级飞侠乐迪接到一项新任务！一个神秘的包裹，一次跨越大洲的派送。', '[\"/images/movie/2023/07/08/5bf5afbdf78e49058917e3e810e06f53.jpg\", \"/images/movie/2023/07/08/ba022fa6124b42d89869ca020473eaa9.jpg\", \"/images/movie/2023/07/08/6f176713bb784aa5a37940b9d76a3699.jpg\", \"/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg\", \"/images/movie/2023/07/08/b73b804fc0cd4c4fbe4e13eae13f5203.jpg\"]', 0);
INSERT IGNORE INTO `sys_movie` VALUES (9, '荒野咖啡馆', 140, '[\"/images/movie/2023/07/08/56439786da7548c188e785da3e9f636b.jpg\"]', '中国大陆', '2029-11-02 00:02:00', 0.00, '在中国西部一座工业小城里，以寒远芳、大梨、小安为代表的年轻人，心中充满了对"远方"的幻想和执着。', '[\"/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg\", \"/images/movie/2023/07/08/78a24b55bdf047e2a3a9737a8650eec2.jpg\", \"/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg\", \"/images/movie/2023/07/08/62a548a7529a4231bcd97150e251868a.jpg\", \"/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg\"]', 0);
