INSERT IGNORE INTO `sys_movie` VALUES (11, '舞者', 100, '[\"/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg\"]', '中国大陆', '2029-05-21 00:00:00', 0.00, '小学六年级的学生夏思梦自幼热爱舞蹈，心中一直藏着一个舞蹈家的梦想。', '[\"/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg\", \"/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg\", \"/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg\", \"/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg\", \"/images/movie/2023/07/08/553600afb5114f358ab825c1fc4644aa.jpeg\"]', 0);
